import React, { useState, useEffect } from 'react';
import { courtierAPI } from '../../services/courtierAPI';

function InviteModal({ onClose, onInvited }) {
  const [form, setForm] = useState({ email: '', password: '', dossier_id: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const set = (k, v) => setForm((f) => ({ ...f, [k]: v }));

  const handleSubmit = async () => {
    if (!form.email || !form.password || !form.dossier_id) {
      setError('Tous les champs sont requis');
      return;
    }
    setLoading(true);
    setError('');
    try {
      await courtierAPI.inviterClient({
        email: form.email,
        password: form.password,
        dossier_id: parseInt(form.dossier_id, 10),
      });
      onInvited();
    } catch (e) {
      setError(e.response?.data?.detail || 'Erreur lors de l\'invitation');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="crt-modal-overlay" onClick={onClose}>
      <div className="crt-modal" onClick={(e) => e.stopPropagation()}>
        <h3>Inviter un client</h3>
        {error && <div style={{ color: '#ff4466', fontSize: 13, marginBottom: 12 }}>{error}</div>}
        <div className="crt-form-group">
          <label>Email client *</label>
          <input className="crt-input" value={form.email} onChange={(e) => set('email', e.target.value)} placeholder="client@example.com" />
        </div>
        <div className="crt-form-group">
          <label>Mot de passe temporaire *</label>
          <input className="crt-input" type="password" value={form.password} onChange={(e) => set('password', e.target.value)} placeholder="••••••••" />
        </div>
        <div className="crt-form-group">
          <label>ID du dossier *</label>
          <input className="crt-input" value={form.dossier_id} onChange={(e) => set('dossier_id', e.target.value)} placeholder="Ex: 42" type="number" />
        </div>
        <div className="crt-modal-actions">
          <button className="crt-btn crt-btn-ghost" onClick={onClose}>Annuler</button>
          <button className="crt-btn crt-btn-primary" onClick={handleSubmit} disabled={loading}>
            {loading ? 'Invitation...' : 'Inviter'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function CourtierClients() {
  const [clients, setClients] = useState([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showInvite, setShowInvite] = useState(false);

  const load = async () => {
    setLoading(true);
    setError('');
    try {
      const res = await courtierAPI.getClients();
      setClients(res.data.clients);
      setTotal(res.data.total);
    } catch {
      setError('Impossible de charger les clients');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { load(); }, []);

  return (
    <div>
      <div className="crt-search-row" style={{ justifyContent: 'flex-end' }}>
        <button className="crt-btn crt-btn-primary" onClick={() => setShowInvite(true)}>
          <i className="ti ti-user-plus" /> Inviter un client
        </button>
      </div>

      <div className="crt-table-wrap">
        <div className="crt-table-header">
          <h2>Clients ({total})</h2>
        </div>

        {loading && <div className="crt-loading"><i className="ti ti-loader" /> Chargement...</div>}
        {error && <div className="crt-error"><i className="ti ti-alert-circle" /> {error}</div>}

        {!loading && !error && (
          <table className="crt-table">
            <thead>
              <tr>
                <th>Email</th>
                <th>Entreprise</th>
                <th>Dossier #</th>
                <th>Statut dossier</th>
                <th>Créé le</th>
              </tr>
            </thead>
            <tbody>
              {clients.map((c) => (
                <tr key={c.id_user}>
                  <td>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                      <div style={{
                        width: 28, height: 28, borderRadius: '50%',
                        background: 'var(--crt-accent-dim)',
                        border: '1px solid var(--crt-accent-border)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        fontSize: 11, color: 'var(--crt-accent)', fontWeight: 700,
                      }}>
                        {c.email[0].toUpperCase()}
                      </div>
                      {c.email}
                    </div>
                  </td>
                  <td style={{ fontWeight: 500 }}>{c.company || '—'}</td>
                  <td style={{ color: 'var(--crt-muted)', fontSize: 13 }}>#{c.dossier_id}</td>
                  <td>
                    {c.dossier_status && (
                      <span className={`crt-badge badge-${c.dossier_status}`}>{c.dossier_status}</span>
                    )}
                  </td>
                  <td style={{ color: 'var(--crt-muted)', fontSize: 13 }}>{c.created_at || '—'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}

        {!loading && !error && clients.length === 0 && (
          <div className="crt-empty">
            <i className="ti ti-users-off" />
            <p>Aucun client associé à vos dossiers</p>
          </div>
        )}
      </div>

      {showInvite && (
        <InviteModal
          onClose={() => setShowInvite(false)}
          onInvited={() => { setShowInvite(false); load(); }}
        />
      )}
    </div>
  );
}
